  // Add init script that intercepts SignalAuth BEFORE modules load
  await page.addInitScript(() => {
    // Mock market data for various tickers
    const MOCK_MARKET = {
      'AAPL': { symbol: 'AAPL', price: 198.52, change: 3.18, change_percent: 1.63, volume: 45200000, vwap: 197.10, updated_at: new Date().toISOString() },
      'MSFT': { symbol: 'MSFT', price: 425.80, change: -2.45, change_percent: -0.57, volume: 22100000, vwap: 426.50, updated_at: new Date().toISOString() },
      'GOOGL': { symbol: 'GOOGL', price: 172.33, change: 1.05, change_percent: 0.61, volume: 18700000, vwap: 171.80, updated_at: new Date().toISOString() },
      'TSLA': { symbol: 'TSLA', price: 245.12, change: -8.67, change_percent: -3.42, volume: 67800000, vwap: 248.90, updated_at: new Date().toISOString() },
      'NVDA': { symbol: 'NVDA', price: 892.40, change: 15.30, change_percent: 1.74, volume: 38500000, vwap: 885.20, updated_at: new Date().toISOString() },
      'META': { symbol: 'META', price: 512.75, change: 0.00, change_percent: 0.00, volume: 15300000, vwap: 512.75, updated_at: new Date().toISOString() },
      'AMZN': { symbol: 'AMZN', price: 186.20, change: 2.85, change_percent: 1.55, volume: 31200000, vwap: 184.90, updated_at: new Date().toISOString() },
    };

    const MOCK_TIER = {
      tier: 'max',
      features: {
        terminal_access: true,
        ai_analysis: true,
        ai_sentiment: true,
        ai_ticker_recommendations: true,
        deduplication: true,
        api_access: true,
        export_csv: true
      }
    };

    const MOCK_USER = {
      uid: 'test-max-user-001',
      email: 'max-tester@instnews.net',
      displayName: 'Max Tester',
      photoURL: null
    };

    // Store original fetch
    const _origFetch = window.fetch;

    // Intercept when auth module sets window.SignalAuth
    let _realSignalAuth = null;
    let _authChangeCallbacks = [];

    Object.defineProperty(window, 'SignalAuth', {
      configurable: true,
      get() { return _realSignalAuth; },
      set(val) {
        _realSignalAuth = val;

        // Wrap key methods
        const origInit = val.init;
        const origOnAuthChange = val.onAuthChange;
        const origFetch = val.fetch;
        const origIsSignedIn = val.isSignedIn;
        const origGetUser = val.getUser;
        const origGetToken = val.getToken;

        val.isSignedIn = () => true;
        val.getUser = () => MOCK_USER;
        val.getToken = () => 'mock-token-max-tier';

        val.init = () => {
          // Trigger auth change callbacks with mock user after a tick
          setTimeout(() => {
            _authChangeCallbacks.forEach(cb => cb(MOCK_USER));
          }, 100);
          return Promise.resolve();
        };

        val.onAuthChange = (cb) => {
          _authChangeCallbacks.push(cb);
          // Also register with original
          origOnAuthChange.call(val, cb);
        };

        val.fetch = (url, options) => {
          // Intercept /api/auth/tier
          if (url.includes('/auth/tier')) {
            return Promise.resolve(new Response(JSON.stringify(MOCK_TIER), {
              status: 200,
              headers: { 'Content-Type': 'application/json' }
            }));
          }
          // Intercept /api/market/:symbol
          const marketMatch = url.match(/\/api\/market\/([A-Z]+)$/);
          if (marketMatch) {
            const symbol = marketMatch[1];
            const data = MOCK_MARKET[symbol] || { symbol, price: 100.00, change: 0.50, change_percent: 0.50, volume: 1000000, vwap: 99.75, updated_at: new Date().toISOString() };
            return Promise.resolve(new Response(JSON.stringify(data), {
              status: 200,
              headers: { 'Content-Type': 'application/json' }
            }));
          }
          // Pass through for news and other endpoints
          options = options || {};
          options.headers = options.headers || {};
          options.headers['Authorization'] = 'Bearer mock-token-max-tier';
          return _origFetch(url, options);
        };
      }
    });
  });

  // Now navigate to the terminal
  await page.goto('http://localhost:8000/terminal.html', { waitUntil: 'networkidle' });
  await page.waitForTimeout(2000);
  return await page.title();
}

