() => {
  // Check if ticker column is visible in the table headers
  const headers = document.querySelectorAll('th');
  const headerTexts = Array.from(headers).map(h => h.textContent.trim());

  // Also check the ticker checkbox state and manually dispatch change event
  const items = document.querySelectorAll('.col-toggle-item');
  let tickerCheckbox = null;
  for (const item of items) {
    if (item.textContent.includes('Ticker')) {
      tickerCheckbox = item.querySelector('input[type="checkbox"]');
      break;
    }
  }

  // Dispatch change event to ensure handler fires
  if (tickerCheckbox && tickerCheckbox.checked) {
    tickerCheckbox.dispatchEvent(new Event('change', { bubbles: true }));
  }

  return {
    headers: headerTexts,
    tickerChecked: tickerCheckbox ? tickerCheckbox.checked : null,
    colId: tickerCheckbox ? tickerCheckbox.dataset.colId : null
  };
}

