() => {
  // Intercept the /api/news response to inject target_asset data
  // Save original SignalAuth.fetch for news
  const origFetch = window.SignalAuth.fetch;

  // Create a wrapper that adds target_asset to news responses
  const TICKER_MAP = {
    'Microsoft': 'MSFT',
    'Palantir': 'PLTR',
    'Oracle': 'ORCL',
    'Micron': 'MU', 
    'Zoom': 'ZM',
    'Qualcomm': 'QCOM',
    'ChargePoint': 'CHPT',
    'LVMH': 'LVMH',
    'Conagra': 'CAG',
    'GameStop': 'GME',
    'Uber': 'UBER',
    'Airbnb': 'ABNB',
    'Bloom Energy': 'BE',
    'CoStar': 'CSGP',
    'Aptiv': 'APTV',
    'stock': null, // generic
  };

  function assignTicker(title) {
    for (const [keyword, ticker] of Object.entries(TICKER_MAP)) {
      if (ticker && title.toLowerCase().includes(keyword.toLowerCase())) {
        return ticker;
      }
    }
    return null;
  }

  window.SignalAuth.fetch = async (url, options) => {
    const res = await origFetch(url, options);

    // Only intercept /api/news
    if (url.includes('/api/news')) {
      const data = await res.json();
      const items = data.items || data;

      // Inject target_asset based on title keywords
      for (const item of items) {
        const ticker = assignTicker(item.title || '');
        if (ticker) {
          item.target_asset = ticker;
          item.ai_analyzed = true;
        }
      }

      return new Response(JSON.stringify(data), {
        status: res.status,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return res;
  };

  // Now trigger a refresh to reload news with injected tickers
  const refreshBtn = document.getElementById('btn-refresh');
  if (refreshBtn) refreshBtn.click();

  return 'News fetch interceptor installed, refresh triggered';
}

