() => {
  // Install a counter to track market fetch calls
  window._marketFetchCount = 0;
  window._marketFetchLog = [];

  const currentFetch = window.SignalAuth.fetch;
  window.SignalAuth.fetch = async (url, options) => {
    if (url.includes('/api/market/')) {
      window._marketFetchCount++;
      window._marketFetchLog.push({ time: Date.now(), url: url });
    }
    return currentFetch(url, options);
  };

  return `Market fetch tracker installed. Current count: ${window._marketFetchCount}`;
}

