input.function:
() => {
  const count = window._marketFetchCount;
  const log = window._marketFetchLog || [];

  // Group by timestamp (within 1 second = same batch)
  const batches = [];
  let currentBatch = [];
  let lastTime = 0;
  for (const entry of log) {
    if (entry.time - lastTime > 1000 && currentBatch.length > 0) {
      batches.push({ time: new Date(currentBatch[0].time).toISOString(), count: currentBatch.length });
      currentBatch = [];
    }
    currentBatch.push(entry);
    lastTime = entry.time;
  }
  if (currentBatch.length > 0) {
    batches.push({ time: new Date(currentBatch[0].time).toISOString(), count: currentBatch.length });
  }

  return { totalFetches: count, batchCount: batches.length, batches: batches };
}

