input.function:
() => {
  // Detailed color verification
  const badges = document.querySelectorAll('.ticker-badge');
  const results = [];
  for (const badge of badges) {
    const priceEl = badge.querySelector('.ticker-price');
    if (!priceEl) continue;

    const computed = window.getComputedStyle(priceEl);
    results.push({
      ticker: badge.dataset.ticker,
      text: badge.textContent.trim(),
      classes: priceEl.className,
      color: computed.color,
      isUp: priceEl.classList.contains('price-up'),
      isDown: priceEl.classList.contains('price-down'),
      isFlat: priceEl.classList.contains('price-flat'),
      cursor: window.getComputedStyle(badge).cursor
    });
  }
  return results;
}

